import { Row } from "react-bootstrap";
import Accordion from "react-bootstrap/Accordion";

function QADropdown({ data }) {
     data=[]
  return (  
    <Row>
      <Accordion>
        {
        data.length > 0 ? (

        data.map((item) => (
          <Accordion.Item eventKey={item.id}>
            <Accordion.Header>
              <div className="m-auto">{item.question}</div>
            </Accordion.Header>
            {item.answers.map((answer) => (
            <Accordion.Body>
            <div className="px-3 d-inline">{answer.answer}</div>
              <button className="btn-color">مسح السؤال</button>
          </Accordion.Body>
          ))}
          </Accordion.Item>
        ))
    ):(
        <div className="font-decription">لا يوجد بيانات</div>
    )



        }


      </Accordion>
    </Row>
  );
}

export default QADropdown;
